VALUES
  ('judicial-57112235-moex-00407', 'judicial-57112235', 'judicial-57112235-moex-112-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依行刑累進處遇條例第28條之1有關受刑人縮短刑期之規定，下列敘述何者錯誤？', '["第四級受刑人，每執行1個月縮短刑期1日", "第三級受刑人，每執行1個月縮短刑期2日", "第二級受刑人，每執行1個月縮短刑期4日", "第一級受刑人，每執行1個月縮短刑期6日"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "7bed571ea996", "answer_pdf_sha1": "beb2a64cc59d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00408', 'judicial-57112235', 'judicial-57112235-moex-112-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '有關監獄對於受刑人施以之處分，下列何者不需通知其指定之家屬或最近親屬？', '["施以固定保護", "收容於保護室", "施用戒具", "施以懲罰"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "7bed571ea996", "answer_pdf_sha1": "beb2a64cc59d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00409', 'judicial-57112235', 'judicial-57112235-moex-112-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '調查人員對於適用累進處遇之受刑人，應依據調查所得之結果，作為研議處遇計畫之基礎，有關受刑 人犯次及累進處遇分數之規定，下列敘述何者錯誤？', '["初犯：指無入監執行之紀錄者", "再犯：指有犯罪前科，但不合刑法第47條之規定者", "累犯：指受徒刑之執行完畢，或一部之執行而赦免後，5年以內故意再犯有期徒刑以上之罪者", "再犯者責任分數與初犯者相同"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "7bed571ea996", "answer_pdf_sha1": "beb2a64cc59d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00410', 'judicial-57112235', 'judicial-57112235-moex-112-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '受刑人不宜施以固定保護，已施用者應即終止，下列何種情形符合此項規定？', '["糖尿病患", "洗腎病患", "有癲癇發作史", "有躁鬱症發作史"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "7bed571ea996", "answer_pdf_sha1": "beb2a64cc59d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00411', 'judicial-57112235', 'judicial-57112235-moex-112-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '有關受刑人外出實施辦法規定，下列敘述何者錯誤？', '["受刑人外出時無須戒護，但監獄認有必要時，在不妨礙外出目的之限度內，得對受刑人施以電子監 控措施", "受刑人每日外出時間，自當日上午6時至下午9時之間為原則", "外出受刑人有於監外留宿必要者，監獄得指定其留宿處所，並報監督機關核准", "受刑人外出期間所需費用，得自行負擔；但參與公益服務者，得收取相關機關（構）、團體之報酬"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "7bed571ea996", "answer_pdf_sha1": "beb2a64cc59d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00412', 'judicial-57112235', 'judicial-57112235-moex-112-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '有關出入戒護區接受檢查，下列敘述何者正確？', '["出入戒護區者應接受檢查。但有緊急狀況或特殊事由，經監獄長官之准許，得免予檢查", "監獄禁止拒絕檢查之人員進入戒護區，應定期陳報監督機關備查", "出戒護區接受檢查時，查獲未經許可攜帶之通訊器材進入戒護區者，可依監獄行刑法移送裁處罰鍰", "對規避、妨害或拒絕監獄依傳染病防治法令所為之傳染病監控防疫措施者，監獄禁止其進入戒護區 應經當地衛生主管機關同意"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "7bed571ea996", "answer_pdf_sha1": "beb2a64cc59d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00413', 'judicial-57112235', 'judicial-57112235-moex-112-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依監獄施用戒具與施以固定保護及保護室收容管理辦法之規定，關於施以固定保護應注意事項，下列 敘述何者正確？', '["施以固定保護每次不得逾24小時", "應將受刑人固定保護於推（病）床，並嚴禁固定於擔架上", "受刑人肢體上有動靜脈俌管者，應於該肢體部位使用保護性約束工具", "施以固定保護得遮蔽受刑人之視線"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "7bed571ea996", "answer_pdf_sha1": "beb2a64cc59d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00414', 'judicial-57112235', 'judicial-57112235-moex-112-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', 'A監獄因嚴重超額收容，經法務部矯正署依監獄行刑法第17條第1項核定機動調整移監30名受刑人 移至B監獄。A監獄不得挑選下列那項條件之受刑人移到B監獄？', '["由其他監獄移入A監獄執行已滿6個月，但未滿1年", "殘餘刑期2個月以上，但未滿1年", "1年後將符合假釋要件", "持有衛生福利部疾病管制署核發之全國醫療服務卡"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "7bed571ea996", "answer_pdf_sha1": "beb2a64cc59d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00415', 'judicial-57112235', 'judicial-57112235-moex-112-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '宗教宣導，係監獄教化手段之一，監獄行刑法有關監獄實施宗教宣導之規定，下列敘述何者錯誤？', '["受刑人有信仰宗教之自由，監獄不得以宗教活動有妨害監獄秩序或安全而加以限制或禁止", "監獄得依受刑人請求安排適當之宗教師，實施教誨", "監獄得邀請宗教人士舉行有助於受刑人之宗教活動", "受刑人得持有與其宗教信仰有關之物品或典籍。但有妨礙監獄秩序、安全及管理之情形，得限制或 禁止之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "7bed571ea996", "answer_pdf_sha1": "beb2a64cc59d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00416', 'judicial-57112235', 'judicial-57112235-moex-112-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '有關監獄受刑人監外就醫之規定，下列敘述何者正確？', '["受刑人因受傷或罹患疾病，有醫療急迫情形，或經醫師診治後認有必要，監獄得戒送醫療機構或病 監醫治", "監獄戒送受刑人外醫之交通費用，應一律由受刑人自行負擔，其在醫療機構醫治期間，視為在監執行", "受刑人經戒送外醫，仍不能或無法為適當之醫治者，監獄得報請監督機關參酌醫囑後核准保外醫治， 保外醫治期間，算入刑期", "懷胎4月以上或生產未滿2月者，得準用戒護外醫或保外醫治方式辦理"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "7bed571ea996", "answer_pdf_sha1": "beb2a64cc59d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL)
